def is_prime(num):
    if num < 2:
        return False
    for i in range(2, int(num**0.5) + 1):
        if num % i == 0:
            return False
    return True

def fibonacci(n):
    a, b = 0, 1
    for _ in range(n):
        a, b = b, a + b
    return a

def prime_fib(n):
    count, index = 0, 1
    while count < n:
        fib_number = fibonacci(index)
        if is_prime(fib_number):
            count += 1
        index += 1
    return fibonacci(index - 1)
